class Solution {
public:
    long long minimumCost(string s) {
        int n = s.size();
        long long cost = 0;
        for (int i = 1; i < n; ++i) {
            if (s[i] != s[i - 1]) {
                cost += std::min(i, n - i);
            }
        }
        return cost;
    }
};
